// Override: when batch status → Completed, add producedQty to finished goods inventory
route('POST', '/api/production/:id/complete', async (req, res, id) => {
  const session = requireAuth(req, res);
  if (!session) return;
  const db = loadDB();
  const batch = db.production.find(b => b.id === id);
  if (!batch) return err(res, 'Batch not found', 404);
  const data = await body(req);
  const producedQty = parseFloat(data.producedQty) || batch.plannedQty;
  batch.status = 'Completed';
  batch.qcStatus = 'Passed';
  batch.producedQty = producedQty;
  batch.completedAt = new Date().toISOString();
  // Add produced qty to finished goods inventory
  const added = adjustInventoryQty(db, batch.productId, batch.productName, producedQty);
  if (!added) {
    // Create new inventory entry if product not yet in inventory
    const prod = (db.products||[]).find(p => p.id === batch.productId);
    db.inventory.push({
      id: uid('INV'), productId: batch.productId, productName: batch.productName,
      sku: prod ? prod.sku : '', category: 'Finished Goods',
      qty: producedQty, unit: prod ? prod.unit : 'pcs', costPerUnit: 0,
      zone: 'WH-A Zone 1 · -18°C', batch: batch.id,
      expiryDate: '', minQty: 0, status: 'In Stock',
      createdAt: new Date().toISOString(),
    });
  }
  saveDB(db);
  json(res, { ok: true, batch, inventoryUpdated: true });
});

// Sales Orders — auto-create invoice on new order
crud('salesOrders', 'SO', {
  afterCreate: (order, db) => {
    db.invoices = db.invoices || [];
    db.invoices.push({
      id: uid('INV-A'), date: order.date || today(),
      dueDate: addDays(order.date || today(), 30),
      customerId: order.customerId, customerName: order.customerName,
      orderId: order.id, subtotal: order.subtotal||0, tax: order.tax||0,
      total: order.total||0, paid: 0, status: 'Unpaid', notes: '',
      items: order.items || [],
      createdAt: new Date().toISOString(),
    });
    // Deduct invoiced quantities from finished goods inventory
    (order.items || []).forEach(item => {
      if (item.productId || item.productName) {
        adjustInventoryQty(db, item.productId, item.productName, -(item.qty || 0));
      }
    });
  }
});

// Purchases — auto-approve + create supplier bill immediately
crud('purchases', 'PO', {
  afterCreate: (po, db) => {
    // Auto-approve: all purchases are immediate
    po.status = 'Approved';
    // Create supplier bill — due on dueDate from PO
    db.supplierBills = db.supplierBills || [];
    db.supplierBills.push({
      id: uid('BILL'),
      date: po.date || today(),
      dueDate: po.dueDate || addDays(po.date || today(), po.paymentDays || 0),
      supplierId: po.supplierId, supplierName: po.supplierName,
      purchaseId: po.id, total: po.total||0, paid: 0, status: 'Unpaid',
      items: po.items || [],
      createdAt: new Date().toISOString(),
    });
  }
});

crud('invoices',      'INV-A');
crud('supplierBills', 'BILL');

// Mark invoice paid
route('POST', '/api/invoices/:id/pay', async (req, res, id) => {
  if (!requireAuth(req, res)) return;
  const db = loadDB();
  const inv = db.invoices.find(i => i.id === id);
  if (!inv) return err(res, 'Not found', 404);
  const data = await body(req);
  const payment = parseFloat(data.amount) || inv.total;
  inv.paid = Math.min((inv.paid||0) + payment, inv.total);
  inv.status = inv.paid >= inv.total ? 'Paid' : inv.paid > 0 ? 'Partial' : 'Unpaid';
  if (inv.paid >= inv.total) inv.paidDate = today();
  const cust = db.customers.find(c => c.id === inv.customerId);
  if (cust) cust.balance = Math.max(0, (cust.balance||0) - payment);
  saveDB(db);
  json(res, inv);
});

// Mark supplier bill paid
route('POST', '/api/supplierBills/:id/pay', async (req, res, id) => {
  if (!requireAuth(req, res)) return;
  const db = loadDB();
  const bill = db.supplierBills.find(b => b.id === id);
  if (!bill) return err(res, 'Not found', 404);
  const data = await body(req);
  const payment = parseFloat(data.amount) || bill.total;
  bill.paid = Math.min((bill.paid||0) + payment, bill.total);
  bill.status = bill.paid >= bill.total ? 'Paid' : 'Partial';
  const sup = db.suppliers.find(s => s.id === bill.supplierId);
  if (sup) sup.balance = Math.max(0, (sup.balance||0) - payment);
  saveDB(db);
  json(res, bill);
});

// Dashboard
route('GET', '/api/dashboard', (req, res) => {
  if (!requireAuth(req, res)) return;
  const db = loadDB();
  const invValue     = db.inventory.reduce((s,i)=>s+(i.qty||0)*(i.costPerUnit||0),0);
  const receivables  = db.invoices.filter(i=>i.status!=='Paid').reduce((s,i)=>s+(i.total||0)-(i.paid||0),0);
  const payables     = db.supplierBills.filter(b=>b.status!=='Paid').reduce((s,b)=>s+(b.total||0)-(b.paid||0),0);
  const revenue      = db.invoices.filter(i=>i.status==='Paid').reduce((s,i)=>s+(i.total||0),0);
  const expenses     = db.expenses.reduce((s,e)=>s+(e.amount||0),0);
  const lowStock     = db.inventory.filter(i=>i.status!=='In Stock');
  const expiring     = db.inventory.filter(i=>i.expiryDate && daysUntil(i.expiryDate)<30);
  const overdueAR    = db.invoices.filter(i=>i.status==='Overdue');
  const overdueBills = db.supplierBills.filter(b=>b.status!=='Paid'&&daysUntil(b.dueDate)<0);
  const now = new Date();
  const revenueChart = Array.from({length:8},(_,i)=>{
    const d = new Date(now.getFullYear(), now.getMonth()-(7-i), 1);
    const label = d.toLocaleString('en',{month:'short'});
    // Include all invoices created in that month (billed amount) for the chart
    const value = db.invoices.filter(inv=>{
      if(!inv.date) return false;
      const dt=new Date(inv.date+'T12:00:00');
      return dt.getMonth()===d.getMonth()&&dt.getFullYear()===d.getFullYear();
    }).reduce((s,inv)=>s+(inv.total||0),0);
    return { label, value: Math.round(value) };
  });
  json(res, {
    invValue, receivables, payables, revenue, expenses, netProfit: revenue-expenses,
    lowStockCount: lowStock.length, expiringCount: expiring.length,
    overdueARCount: overdueAR.length, overdueBillsCount: overdueBills.length,
    totalCustomers: db.customers.length, totalSuppliers: db.suppliers.length,
    totalProducts: db.products.length, pendingOrders: db.salesOrders.filter(o=>o.status==='Pending').length,
    revenueChart, recentOrders: db.salesOrders.slice(-5).reverse(),
    lowStockItems: lowStock.slice(0,6), expiringItems: expiring.slice(0,6),
    overdueAR, overdueBills,
  });
});

// ─── USER MANAGEMENT (admin only) ─────────────────────────

route('GET', '/api/users', (req, res) => {
  const session = requireAuth(req, res);
  if (!session) return;
  if (session.role !== 'admin') return err(res, 'Admin only', 403);
  const users = getUsers().map(u => ({ ...u, password: '••••••••' })); // mask passwords
  json(res, users);
});

route('POST', '/api/users', async (req, res) => {
  const session = requireAuth(req, res);
  if (!session) return;
  if (session.role !== 'admin') return err(res, 'Admin only', 403);
  const db = loadDB();
  const data = await body(req);
  if (!data.username || !data.password) return err(res, 'Username and password required');
  db.users = db.users || [];
  if (db.users.find(u => u.username.toLowerCase() === data.username.toLowerCase())) {
    return err(res, 'Username already exists');
  }
  const user = {
    id: uid('USR'), username: data.username, password: data.password,
    role: data.role || 'user', displayName: data.displayName || data.username, active: true,
    createdAt: new Date().toISOString(), createdBy: session.username,
  };
  db.users.push(user);
  saveDB(db);
  json(res, { ...user, password: '••••••••' }, 201);
});

route('PUT', '/api/users/:id', async (req, res, id) => {
  const session = requireAuth(req, res);
  if (!session) return;
  if (session.role !== 'admin') return err(res, 'Admin only', 403);
  const db = loadDB();
  db.users = db.users || [];
  const idx = db.users.findIndex(u => u.id === id);
  if (idx === -1) return err(res, 'User not found', 404);
  const data = await body(req);
  // Don't allow removing last admin
  if (data.role && data.role !== 'admin') {
    const admins = db.users.filter(u => u.role === 'admin' && u.id !== id);
    if (admins.length === 0) return err(res, 'Cannot remove last admin');
  }
  db.users[idx] = { ...db.users[idx], ...data, updatedAt: new Date().toISOString() };
  saveDB(db);
  json(res, { ...db.users[idx], password: '••••••••' });
});

route('DELETE', '/api/users/:id', (req, res, id) => {
  const session = requireAuth(req, res);
  if (!session) return;
  if (session.role !== 'admin') return err(res, 'Admin only', 403);
  if (session.userId === id) return err(res, 'Cannot delete your own account');
  const db = loadDB();
  db.users = db.users || [];
  const admins = db.users.filter(u => u.role === 'admin' && u.id !== id);
  const target = db.users.find(u => u.id === id);
  if (target && target.role === 'admin' && admins.length === 0) {
    return err(res, 'Cannot delete last admin');
  }
  db.users = db.users.filter(u => u.id !== id);
  saveDB(db);
  json(res, { ok: true });
});

